tlCollisionVolumeOwnerChunk::tlCollisionVolumeOwnerChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Simulation::Collision::OWNER);
    ident = Simulation::Collision::OWNER;

    tlFile* f = ch->GetFile();

    numnames = f->GetLong();
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Simulation::Collision::OWNER);
    }
}

void
tlCollisionVolumeOwnerChunk::Init()
{
    ident = Simulation::Collision::OWNER;
    numnames = 0;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Simulation::Collision::OWNER);
    }
}

long 
tlCollisionVolumeOwnerChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += sizeof( numnames );
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlCollisionVolumeOwnerChunk&
tlCollisionVolumeOwnerChunk::operator=(const tlCollisionVolumeOwnerChunk& a)
{

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    numnames = a.numnames;

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlCollisionVolumeOwnerChunk::operator==(const tlDataChunk& a)
{

    const tlCollisionVolumeOwnerChunk* aptr = dynamic_cast<const tlCollisionVolumeOwnerChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(!(numnames == aptr->numnames))
    {
        return false;
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

