tlCollisionVolumeChunk::tlCollisionVolumeChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Simulation::Collision::VOLUME);
    ident = Simulation::Collision::VOLUME;

    tlFile* f = ch->GetFile();

    objectreferenceindex = f->GetLong();
    ownerindex = f->GetLong();
    numsubvolume = f->GetLong();
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Simulation::Collision::VOLUME);
    }
}

void
tlCollisionVolumeChunk::Init()
{
    ident = Simulation::Collision::VOLUME;
    objectreferenceindex = 0;
    ownerindex = 0;
    numsubvolume = 0;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Simulation::Collision::VOLUME);
    }
}

long 
tlCollisionVolumeChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += sizeof( objectreferenceindex );
    s += sizeof( ownerindex );
    s += sizeof( numsubvolume );
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlCollisionVolumeChunk&
tlCollisionVolumeChunk::operator=(const tlCollisionVolumeChunk& a)
{

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    objectreferenceindex = a.objectreferenceindex;
    ownerindex = a.ownerindex;
    numsubvolume = a.numsubvolume;

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlCollisionVolumeChunk::operator==(const tlDataChunk& a)
{

    const tlCollisionVolumeChunk* aptr = dynamic_cast<const tlCollisionVolumeChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(!(objectreferenceindex == aptr->objectreferenceindex))
    {
        return false;
    }
    if(!(ownerindex == aptr->ownerindex))
    {
        return false;
    }
    if(!(numsubvolume == aptr->numsubvolume))
    {
        return false;
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

bool
tlCollisionVolumeChunk::NameCompare(const tlDataChunk& a)
{

    // This chunk has no name, so we must compare the bits
    return operator==(a);
}


