tlDataChunk*
tlCollisionVolumeChunk::LoadSubChunk(tlFile* f)
{
    tlDataChunk *dch;
    tlReadChunk16  ch(f);
    ch.ReadNext();
    unsigned int id = ch.GetID();
 
    switch(id)
    {
    case Simulation::Collision::BBOX:
        dch = new tlBBoxVolumeChunk(&ch);
        break;
    case Simulation::Collision::SPHERE:
        dch = new tlSphereVolumeChunk(&ch);
        break;
    case Simulation::Collision::CYLINDER:
        dch = new tlCylinderVolumeChunk(&ch);
        break;
    case Simulation::Collision::OBBOX:
        dch = new tlOBBoxVolumeChunk(&ch);
        break;
    case Simulation::Collision::WALL:
        dch = new tlWallVolumeChunk(&ch);
        break;
    case Simulation::Collision::VOLUME:
        dch = new tlCollisionVolumeChunk(&ch);
        break;
    default:
        dch = new tlDataChunk(id);
        int size = ch.GetDataSize();
        char* buf = new char[size];
        f->GetBytes(buf, size);
        dch->SetData(buf, size);
        delete buf;
    }
    ch.Skip();
    return dch;
}

