int tlCollisionVectorChunk::sortPriority = -1;

tlCollisionVectorChunk::tlCollisionVectorChunk()
{
    Init();
}

tlCollisionVectorChunk::tlCollisionVectorChunk(const tlCollisionVectorChunk& ch)
{
    Init();
    *this = ch;
}

tlCollisionVectorChunk::~tlCollisionVectorChunk()
{

}

tlCollisionVectorChunk::tlCollisionVectorChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Simulation::Collision::VECTOR);
    ident = Simulation::Collision::VECTOR;

    tlFile* f = ch->GetFile();

    x = f->GetFloat();
    y = f->GetFloat();
    z = f->GetFloat();
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Simulation::Collision::VECTOR);
    }
}

void
tlCollisionVectorChunk::Init()
{
    ident = Simulation::Collision::VECTOR;
    x = 0.0f;
    y = 0.0f;
    z = 0.0f;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Simulation::Collision::VECTOR);
    }
}

long 
tlCollisionVectorChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += sizeof( x );
    s += sizeof( y );
    s += sizeof( z );
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlCollisionVectorChunk&
tlCollisionVectorChunk::operator=(const tlCollisionVectorChunk& a)
{

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    x = a.x;
    y = a.y;
    z = a.z;

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlCollisionVectorChunk::operator==(const tlDataChunk& a)
{

    const tlCollisionVectorChunk* aptr = dynamic_cast<const tlCollisionVectorChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(!(x == aptr->x))
    {
        return false;
    }
    if(!(y == aptr->y))
    {
        return false;
    }
    if(!(z == aptr->z))
    {
        return false;
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

bool
tlCollisionVectorChunk::NameCompare(const tlDataChunk& a)
{

    // This chunk has no name, so we must compare the bits
    return operator==(a);
}


tlDataChunk*
tlCollisionVectorChunk::Create(tlReadChunk16* ch)
{
    tlDataChunk* dtCh = new tlCollisionVectorChunk(ch);
    return dtCh;
}

void
tlCollisionVectorChunk::Write(tlFile* f)
{
    tlWriteChunk16 ch(f, ident);

        f->PutFloat(x);
        f->PutFloat(y);
        f->PutFloat(z);

    ch.ContentFinish();
    for(int subch = 0; subch < subcount; subch++)
    {
        GetSubChunk(subch)->Write(f);
    }
}

void
tlCollisionVectorChunk::Print(int indent, unsigned int printdepth, unsigned int typemask)
{

    if ( printdepth == 0 )
    {
        return;
    }

    printf("%*stlCollisionVectorChunk (%4x)\n",indent,"",(int) ident);
    printf("%*s  X = %f\n",indent,"",x);
    printf("%*s  Y = %f\n",indent,"",y);
    printf("%*s  Z = %f\n",indent,"",z);

    if(subcount)
    {
        printf("%*s  SubChunks (%d):\n",indent,"",subcount);
        for(int subch = 0; subch < subcount; subch++)
        {
            GetSubChunk(subch)->Print(indent+4, printdepth-1, typemask);
        }
    }
}

void
tlCollisionVectorChunk::PrintFormatted(int indent)
{
    printf("%*schunk 0x%04x  \n",indent,"",(int) ident);
    printf("%*s  float %12f # X\n",indent,"",x);
    printf("%*s  float %12f # Y\n",indent,"",y);
    printf("%*s  float %12f # Z\n",indent,"",z);
    if(subcount)
    {
        for(int i=0;i<subcount;i++)
        {
            GetSubChunk(i)->PrintFormatted(indent+2);
        }
    }
    printf("%*sendchunk\n",indent,"");
}

