bool 
tlCollisionVectorChunk::SetFieldValue(int fieldIndex, const char* new_val)
{
    switch(fieldIndex)
    {
        case 0:
        {
            char* end_ptr;
            float tmp;
            tmp = (float)strtod(new_val, &end_ptr);
            if (*end_ptr == 0)
            {
                x = tmp;
                return true;
            }
            return false;
        }
        case 1:
        {
            char* end_ptr;
            float tmp;
            tmp = (float)strtod(new_val, &end_ptr);
            if (*end_ptr == 0)
            {
                y = tmp;
                return true;
            }
            return false;
        }
        case 2:
        {
            char* end_ptr;
            float tmp;
            tmp = (float)strtod(new_val, &end_ptr);
            if (*end_ptr == 0)
            {
                z = tmp;
                return true;
            }
            return false;
        }
        default:
            return false;
    }
}

